 using BitPantry.CommandLine.API;
 using BitPantry.CommandLine.Remote.SignalR.Server.Commands;
+using BitPantry.CommandLine.Remote.SignalR.Server.Files;
 using FluentAssertions;
 using Spectre.Console.Testing;
